.darma-loader-darma-custom-674__spinner {color: var(--loader-color, #ba42ff);
  --loader-bg: var(--loader-bg, #111827);

  background-image: linear-gradient(var(--loader-color, #ba42ff) 35%,var(--loader-secondary-color, #00e1ff));
  width: 100px;
  height: 100px;
  animation: darma-loader-darma-custom-674-spinning82341 1.7s linear infinite;
  text-align: center;
  border-radius: 50px;
  filter: blur(1px);
  box-shadow: 0px -5px 20px 0px var(--loader-color, #ba42ff), 0px 5px 20px 0px var(--loader-secondary-color, #00e1ff);
}

.darma-loader-darma-custom-674__spinner1 {
  background-color: var(--loader-bg, #111827);
  width: 100px;
  height: 100px;
  border-radius: 50px;
  filter: blur(10px);
}

@keyframes darma-loader-darma-custom-674-spinning82341 {
  to {
    transform: rotate(360deg);
  }
}

